import{_ as n,o as e,c as s,ag as t}from"./chunks/framework.ePeAWSvT.js";const h=JSON.parse('{"title":"Command Line & GO Execution","description":"","frontmatter":{},"headers":[],"relativePath":"guide/command-line.md","filePath":"guide/command-line.md"}'),o={name:"guide/command-line.md"};function i(l,a,p,r,c,m){return e(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="command-line-go-execution" tabindex="-1">Command Line &amp; GO Execution <a class="header-anchor" href="#command-line-go-execution" aria-label="Permalink to &quot;Command Line &amp; GO Execution&quot;">​</a></h1><h2 id="global-command-bar" tabindex="-1">Global Command Bar <a class="header-anchor" href="#global-command-bar" aria-label="Permalink to &quot;Global Command Bar&quot;">​</a></h2><p>The <strong>Global Command Bar</strong> appears at the top of the screen (below the System Strip).<br> It always reflects the <strong>focused panel&#39;s</strong> input and executes in that panel.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes tokyo-night tokyo-night vp-code" tabindex="0"><code><span class="line"><span>Panel N &gt; [input field]                    [GO]</span></span></code></pre></div><h2 id="per-panel-command-line" tabindex="-1">Per-Panel Command Line <a class="header-anchor" href="#per-panel-command-line" aria-label="Permalink to &quot;Per-Panel Command Line&quot;">​</a></h2><p>Each panel also has its own command line at the bottom of the panel chrome.<br> Pressing <strong>Ctrl+L</strong> focuses it. The global bar and panel bar are synchronized.</p><h2 id="command-grammar" tabindex="-1">Command Grammar <a class="header-anchor" href="#command-grammar" aria-label="Permalink to &quot;Command Grammar&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes tokyo-night tokyo-night vp-code" tabindex="0"><code><span class="line"><span>&lt;SECURITY&gt; &lt;MNEMONIC&gt; GO</span></span></code></pre></div><h3 id="security-format" tabindex="-1">Security Format <a class="header-anchor" href="#security-format" aria-label="Permalink to &quot;Security Format&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes tokyo-night tokyo-night vp-code" tabindex="0"><code><span class="line"><span>&lt;TICKER&gt; &lt;EXCHANGE&gt;          → AAPL US</span></span>
<span class="line"><span>&lt;TICKER&gt; &lt;EXCHANGE&gt; &lt;TYPE&gt;   → AAPL US Equity (optional — auto-inferred)</span></span>
<span class="line"><span>&lt;PAIR&gt; &lt;TYPE&gt;                → EURUSD Curncy</span></span>
<span class="line"><span>&lt;INDEX&gt; &lt;TYPE&gt;               → SPX Index</span></span>
<span class="line"><span>&lt;ISSUER&gt; &lt;TYPE&gt;              → T US Corp</span></span>
<span class="line"><span>&lt;COMMODITY&gt;                  → CL1 Comdty</span></span></code></pre></div><h3 id="mnemonic-only-global-functions" tabindex="-1">Mnemonic Only (global functions) <a class="header-anchor" href="#mnemonic-only-global-functions" aria-label="Permalink to &quot;Mnemonic Only (global functions)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes tokyo-night tokyo-night vp-code" tabindex="0"><code><span class="line"><span>WEI GO     → World equity indices</span></span>
<span class="line"><span>TOP GO     → Top news</span></span>
<span class="line"><span>ECO GO     → Economic calendar</span></span>
<span class="line"><span>GEO GO     → Global map</span></span></code></pre></div><h3 id="timeframe-modifier" tabindex="-1">Timeframe Modifier <a class="header-anchor" href="#timeframe-modifier" aria-label="Permalink to &quot;Timeframe Modifier&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes tokyo-night tokyo-night vp-code" tabindex="0"><code><span class="line"><span>AAPL US HP 1Y GO    → Historical prices, 1 year</span></span>
<span class="line"><span>AAPL US GP 5D GO    → Chart, 5 days</span></span>
<span class="line"><span>Valid: INTRADAY, 1D, 5D, 1W, 1M, 3M, 6M, 1Y, 3Y, 5Y, 10Y, YTD, MAX</span></span></code></pre></div><h3 id="special-commands" tabindex="-1">Special Commands <a class="header-anchor" href="#special-commands" aria-label="Permalink to &quot;Special Commands&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes tokyo-night tokyo-night vp-code" tabindex="0"><code><span class="line"><span>MENU GO        → Open MENU overlay</span></span>
<span class="line"><span>HELP GO        → Open HELP / TUTOR</span></span>
<span class="line"><span>HL GO          → Open Search overlay (same as Ctrl+K)</span></span>
<span class="line"><span>GRAB GO        → Export panel snapshot to new tab</span></span>
<span class="line"><span>WS &lt;name&gt; GO   → Save or load workspace by name</span></span>
<span class="line"><span>WS DEL &lt;name&gt;  → Delete workspace</span></span>
<span class="line"><span>HD ON / OFF    → Toggle High Density mode</span></span>
<span class="line"><span>LIVE ON / OFF  → Toggle Live streaming mode</span></span>
<span class="line"><span>NP GO          → New pane (tab)</span></span>
<span class="line"><span>NP H GO        → Split horizontal</span></span>
<span class="line"><span>NP V GO        → Split vertical</span></span>
<span class="line"><span>WS:PRESET GO   → Apply workstation preset (MARKET-WALL, NEWSROOM, etc.)</span></span></code></pre></div><h2 id="auto-complete" tabindex="-1">Auto-Complete <a class="header-anchor" href="#auto-complete" aria-label="Permalink to &quot;Auto-Complete&quot;">​</a></h2><p>As you type, a dropdown appears with:</p><ul><li><strong>Matching securities</strong> (ticker, name)</li><li><strong>Matching mnemonics</strong> (code, title)</li></ul><p>Navigate with <strong>↑↓</strong> · Select with <strong>Enter</strong> or <strong>Tab</strong> · Close with <strong>Esc</strong></p><h2 id="typo-correction" tabindex="-1">Typo Correction <a class="header-anchor" href="#typo-correction" aria-label="Permalink to &quot;Typo Correction&quot;">​</a></h2><p>The command parser uses <strong>Levenshtein distance</strong> to find close-enough mnemonics.<br> If you type <strong>WEL</strong> it resolves to <strong>WEI</strong>. If you type <strong>DEES</strong> it resolves to <strong>DES</strong>.</p><h2 id="command-history" tabindex="-1">Command History <a class="header-anchor" href="#command-history" aria-label="Permalink to &quot;Command History&quot;">​</a></h2><ul><li><strong>↑</strong> (when dropdown is closed) → browse previous commands</li><li><strong>↓</strong> → forward through history</li><li>History persists in localStorage per panel</li></ul><h2 id="parse-rules" tabindex="-1">Parse Rules <a class="header-anchor" href="#parse-rules" aria-label="Permalink to &quot;Parse Rules&quot;">​</a></h2><ol><li>Tokens matching known mnemonics (or close-enough) → mnemonic</li><li>Tokens matching market sectors (EQUITY, CORP, CURNCY…) → sector</li><li>Timeframe tokens (1M, 3M…) → timeframe modifier</li><li>Remaining tokens → security name (auto-appended with Equity if no type given)</li></ol>`,26)])])}const g=n(o,[["render",i]]);export{h as __pageData,g as default};
